import anthropic

client = anthropic.Anthropic()   # reads ANTHROPIC_API_KEY from env


def summarise(document: str, max_tokens: int = 200) -> str:
    """Abstractive summarisation via a single prompt."""
    message = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=max_tokens,
        messages=[
            {
                "role": "user",
                "content": f"Summarise the following text in 2–3 sentences:\n\n{document}",
            }
        ],
    )
    return message.content[0].text


def translate(text: str, target_language: str) -> str:
    """Zero-shot machine translation."""
    message = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[
            {
                "role": "user",
                "content": f"Translate the following text into {target_language}. "
                           f"Output only the translation, no explanation.\n\n{text}",
            }
        ],
    )
    return message.content[0].text


def answer_with_context(question: str, context: str) -> str:
    """Open-book QA: answer grounded in provided context (simple RAG pattern)."""
    message = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=256,
        system="Answer only from the provided context. If the answer is not in the context, say so.",
        messages=[
            {
                "role": "user",
                "content": f"Context:\n{context}\n\nQuestion: {question}",
            }
        ],
    )
    return message.content[0].text
